(function () {  'use strict';   var initialized =false;   function initCarShare() {    if (initialized) {      return;   }      var shareBtn =document.getElementById('iaCarShareBtn');    var flyout =document.getElementById('iaCarShareFlyout');    if (!shareBtn||!flyout) {      return;   }     initialized =true;     var shareDataEl =document.getElementById('iaCarShareData');    var backdrop =document.getElementById('iaCarShareBackdrop');    var closeBtn =document.getElementById('iaCarShareCloseBtn');    var copyBtn =document.getElementById('iaCarShareCopyBtn');    var nativeBtn =document.getElementById('iaCarShareNativeBtn');    var urlField =document.getElementById('iaCarShareUrlField');    var appsRoot =document.getElementById('iaCarShareApps');    var defaultTitle =shareBtn.getAttribute('title')||'Поделиться';    var isOpen =false;     var config ={};    if (shareDataEl&&shareDataEl.textContent) {      try {        config =JSON.parse(shareDataEl.textContent.trim());     } catch (e) {        config ={};     }    }      function payload() {      var url =(config.url||'').trim()||window.location.href;      var title =(config.title||'').trim()||document.title;      var warning =(config.disclaimer||'').trim();      if (!warning) {        var notice =document.getElementById('iaCarShareNotice');        if (notice) {          warning =(notice.innerText||'').replace(/\s+/g,' ').trim();       }      }       var body =title+'\n'+url;      var copyFromConfig =(config.copy||'').trim();      var copyText =copyFromConfig||(warning?warning+'\n\n'+body:body);      return {url:url,title:title,warning:warning,copyText:copyText};   }      function markCopied(btn) {      var target =btn||shareBtn;      target.classList.add('is-copied');      if (copyBtn&&target ===copyBtn) {        var label =target.querySelector('.ia-car-share-app-label');        var prev =label?label.textContent:'';        if (label) {          label.textContent ='Скопировано';       }         setTimeout(function () {          target.classList.remove('is-copied');          if (label) {            label.textContent =prev||'Копировать';         }        },2000);        return;     }       shareBtn.setAttribute('title','Ссылка скопирована');      setTimeout(function () {        shareBtn.classList.remove('is-copied');        shareBtn.setAttribute('title',defaultTitle);     },2000);   }      function copyText(text,btn) {      if (!text) {        return;     }       if (navigator.clipboard&&navigator.clipboard.writeText) {        navigator.clipboard           .writeText(text)           .then(function () {            markCopied(btn);         })           .catch(function () {            copyTextFallback(text,btn);         });        return;     }       copyTextFallback(text,btn);   }      function copyTextFallback(text,btn) {      var ta =document.createElement('textarea');      ta.value =text;      ta.setAttribute('readonly','');      ta.style.cssText ='position:fixed;left:-9999px;top:0;opacity:0';      document.body.appendChild(ta);      ta.focus();      ta.select();      try {        if (document.execCommand('copy')) {          markCopied(btn);       }      } catch (e) {}       document.body.removeChild(ta);   }      function sharePayloads(p) {      var fullText =p.warning?p.warning+'\n\n'+p.title+'\n'+p.url:p.title+'\n'+p.url;      return [        {title:p.title,text:fullText,url:p.url},        {title:p.title,text:p.warning,url:p.url},        {title:p.title,text:p.warning+'\n\n'+p.url,url:p.url},        {title:p.title,url:p.url},     ];   }      function tryNativeShare(onDone) {      if (!navigator.share) {        onDone(false);        return;     }        var p =payload();      var list =sharePayloads(p);      var index =0;       function attemptNext() {        if (index>=list.length) {          onDone(false);          return;       }          var data =list[index++];        var promise;         try {          if (navigator.canShare&&!navigator.canShare(data)) {            attemptNext();            return;         }           promise =navigator.share(data);       } catch (err) {          attemptNext();          return;       }          promise           .then(function () {            onDone(true);         })           .catch(function (err) {            if (err&&err.name ==='AbortError') {              onDone(true);              return;           }             attemptNext();         });     }        attemptNext();   }      function positionFlyout() {      var rect =shareBtn.getBoundingClientRect();      var gap =8;      var maxW =Math.min(380,window.innerWidth-16);      flyout.style.width =maxW+'px';       if (window.innerWidth<768) {        flyout.style.position ='fixed';        flyout.style.top ='auto';        flyout.style.bottom ='0';        flyout.style.left ='0';        flyout.style.right ='0';        flyout.style.width ='';        return;     }        flyout.style.position ='fixed';      flyout.style.bottom ='auto';      flyout.style.left ='auto';      flyout.style.right =Math.max(8,window.innerWidth-rect.right)+'px';       flyout.hidden =false;      flyout.removeAttribute('hidden');      var flyH =flyout.offsetHeight;      var top =rect.bottom+gap;      if (top+flyH>window.innerHeight-8) {        top =Math.max(8,rect.top-gap-flyH);     }       flyout.style.top =top+'px';   }      function openFlyout() {      if (urlField) {        urlField.value =payload().url;     }       flyout.hidden =false;      flyout.removeAttribute('hidden');      flyout.classList.add('is-open');      shareBtn.setAttribute('aria-expanded','true');      isOpen =true;       if (backdrop) {        backdrop.hidden =false;        backdrop.removeAttribute('hidden');        backdrop.classList.add('is-visible');     }        positionFlyout();      document.body.classList.add('ia-car-share-open');       var firstFocus =nativeBtn||closeBtn;      if (firstFocus) {        setTimeout(function () {          firstFocus.focus();       },30);     }    }      function closeFlyout() {      if (!isOpen) {        return;     }       flyout.classList.remove('is-open');      flyout.hidden =true;      flyout.setAttribute('hidden','');      shareBtn.setAttribute('aria-expanded','false');      isOpen =false;       if (backdrop) {        backdrop.classList.remove('is-visible');        backdrop.hidden =true;        backdrop.setAttribute('hidden','');     }        document.body.classList.remove('ia-car-share-open');      shareBtn.focus();   }      function toggleFlyout() {      if (isOpen) {        closeFlyout();     } else {        openFlyout();     }    }      function openNativeShare() {      closeFlyout();      tryNativeShare(function (ok) {        if (!ok) {          copyText(payload().copyText,copyBtn);       }      });   }      function bindAppLinks() {      if (!appsRoot) {        return;     }        var p =payload();      var encodedUrl =encodeURIComponent(p.url);      var encodedText =encodeURIComponent(p.copyText);       appsRoot.querySelectorAll('[data-share-app]').forEach(function (el) {        var kind =el.getAttribute('data-share-app');        if (kind ==='whatsapp') {          el.href ='https://wa.me/?text='+encodedText;       } else if (kind ==='telegram') {          el.href =            'https://t.me/share/url?url='+            encodedUrl+            '&text='+            encodeURIComponent((p.warning?p.warning+'\n\n':'')+p.title);       } else if (kind ==='copy') {          el.href ='#';          el.addEventListener('click',function (e) {            e.preventDefault();            copyText(p.copyText,el);         });       } else if (kind ==='native') {          el.href ='#';          el.addEventListener('click',function (e) {            e.preventDefault();            openNativeShare();         });       }      });   }      shareBtn.addEventListener('click',function (e) {      e.preventDefault();      e.stopPropagation();      toggleFlyout();   });     if (closeBtn) {      closeBtn.addEventListener('click',function (e) {        e.preventDefault();        closeFlyout();     });   }      if (backdrop) {      backdrop.addEventListener('click',closeFlyout);   }      if (nativeBtn) {      nativeBtn.addEventListener('click',function (e) {        e.preventDefault();        openNativeShare();     });   }      if (copyBtn) {      copyBtn.addEventListener('click',function (e) {        e.preventDefault();        copyText(payload().copyText,copyBtn);     });   }      document.addEventListener('keydown',function (e) {      if (e.key ==='Escape'&&isOpen) {        closeFlyout();     }    });     document.addEventListener('click',function (e) {      if (!isOpen) {        return;     }       var t =e.target;      if (!t||!t.closest) {        return;     }       if (t.closest('.ia-car-share-flyout')||t.closest('#iaCarShareBtn')) {        return;     }       closeFlyout();   });     window.addEventListener('resize',function () {      if (isOpen) {        positionFlyout();     }    });     bindAppLinks(); }    function boot() {    initCarShare(); }    if (document.readyState ==='loading') {    document.addEventListener('DOMContentLoaded',boot); } else {    boot(); }   window.addEventListener('load',boot);})();
